mapper.select:
SELECT APPROVAL_YN
FROM mhdb.TB_APPROVAL_LINE
WHERE 1=1
  AND USER_CD = #{userCd}
  AND APPROVAL_REQ_ID = #{approvalReqId}
  AND APPROVAL_DIV_CD = #{approvalDivCd}
  AND APPROVAL_LINE_INDEX = #{lineIndex}

mapper.update:
UPDATE mhdb.TB_APPROVAL_LINE
SET
	APPROVAL_YN = #{approvalYn},
	APPROVAL_REJECT_DOCU = #{approvalRejectDocu},
	APPROVAL_REQ_DOCU = #{approvalReqDocu},
	APPROVAL_DATE = #{approvalDate}

	,APPROVAL_LINE_USER_ID = #{approvalLineUserId}


	,APPROVAL_LINE_USER_NM = #{approvalLineUserNm}

WHERE 1=1
  AND USER_CD = #{userCd}
  AND APPROVAL_REQ_ID = #{approvalReqId}
  AND APPROVAL_DIV_CD = #{approvalDivCd}
  AND APPROVAL_LINE_USER_ID = #{whereApprovalLineUserId}
  AND APPROVAL_LINE_INDEX = #{approvalLineIndex}

UPDATE mhdb.TB_APPROVAL_LINE
SET BEFORE_APPLY_YN = 'Y'
WHERE 1=1
  AND APPROVAL_REQ_ID = #{approvalReqId}
  AND APPROVAL_LINE_INDEX = #{lineIndex}

UPDATE mhdb.TB_APPROVAL_REQ
SET APPROVAL_DATE = #{approvalDate}

	,AUTH = #{auth}

WHERE 1=1
  AND USER_CD = #{userCd}
  AND APPROVAL_DIV_CD = #{approvalDivCd}
  AND APPROVAL_REQ_ID = #{approvalReqId}

UPDATE mhdb.TB_APPROVAL_LINE
SET APPROVAL_LINE_USER_NM = #{userNm}
WHERE 1=1
  AND APPROVAL_REQ_ID = #{approvalReqId}
  AND APPROVAL_LINE_INDEX = #{lineIndex}

